# Автосгенерированный файл: шрифты DejaVu Sans (сжаты zlib + base64) для генерации PDF с кириллицей
import zlib, base64

DEJAVU_REGULAR_B64 = ""
DEJAVU_BOLD_B64 = ""

def get_regular_bytes():
    return zlib.decompress(base64.b64decode(DEJAVU_REGULAR_B64))

def get_bold_bytes():
    return zlib.decompress(base64.b64decode(DEJAVU_BOLD_B64))
